NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
void solve()
{
	int a,b,ca,cb,fa;
	cin>>a>>b>>ca>>cb>>fa;
	if(a+b/cb*ca>=fa)
	{
		cout<<"0\n";
		return;
	}
	auto f1=[&]()
	{
		fa-=a;
		int x=(fa-1)%ca;
		int usaco=(fa-x+ca-1)/ca;
		int y=usaco*cb-b;
		return x+y;
	};
	auto f2=[&]()
	{
		int y=cb-1-(b%cb);
		int z=(fa-((b+y)/cb*ca)-a);
		return y+z;
	};
	cout<<max(f1(),f2())<<'\n';
	return;
} 
signed main(void)
{

